/**
 * Canonical schema for EcoVibe Floors blog post frontmatter.
 *
 * This is the single source of truth for:
 *   - Which fields exist in a blog post
 *   - Whether each field is required or optional
 *   - Where each field goes in Firestore (shared top-level, translation-specific, or skipped)
 *   - What type/values are valid
 *
 * Used by: publish-blog-post.js (validation + field routing)
 * Template generated by: scripts/generate-frontmatter-template.js → tools/writing/blog-post-frontmatter.yaml
 *
 * If you add or rename a field, update ONLY this file.
 * publish-blog-post.js derives SHARED_FIELDS, TRANSLATION_FIELDS, and validate() from here automatically.
 */

export const BLOG_POST_SCHEMA = {

    // ── Shared fields — written to top-level of blogPosts/{slug} ──────────────

    slug: {
        target: 'shared',
        required: true,
        type: 'string',
        pattern: /^[a-z0-9-]+$/,
        note: 'English canonical slug — Latin + hyphens only, shared by BG and EN drafts',
    },
    strategyId: {
        target: 'shared',
        required: true,
        type: 'string',
        note: 'e.g. P1, P1-C2, UFH-1',
    },
    postType: {
        target: 'shared',
        required: false,
        type: 'string',
        enum: ['pillar', 'cluster', 'cross-pillar', 'brand'],
    },
    phase: {
        target: 'shared',
        required: false,
        type: 'number',
        note: '1–5 — content pillar phase',
    },
    category: {
        target: 'shared',
        required: true,
        type: 'string',
        enum: ['engineered-parquet', 'hybrid', 'spc-lvt', 'comparison', 'brand'],
    },
    schemaType: {
        target: 'shared',
        required: false,
        type: 'string',
        enum: ['Article', 'HowTo', 'FAQPage'],
        note: 'JSON-LD schema.org type',
    },
    heroImage: {
        target: 'shared',
        required: true,
        type: 'string',
        pattern: /^products\/.+\.webp$/,
        note: 'Firebase Storage path — products/{collection}/{subcollection}/{sku}/full/{filename}.webp',
    },
    isPartOf: {
        target: 'shared',
        required: false,
        type: 'string',
        nullable: true,
        note: 'Strategy ID of parent pillar (for clusters); null for pillars',
    },
    hasPart: {
        target: 'shared',
        required: false,
        type: 'array',
        note: 'Array of cluster strategy IDs (for pillars); [] for clusters',
    },
    linksTo: {
        target: 'shared',
        required: false,
        type: 'array',
        note: 'Strategy IDs this post links to internally',
    },
    relatedPostSlugs: {
        target: 'shared',
        required: false,
        type: 'array',
        note: 'Strategy IDs of related posts shown in sidebar/footer',
    },
    featuredProducts: {
        target: 'shared',
        required: false,
        type: 'array',
        itemSchema: {
            name:  { type: 'string', required: true },
            brand: { type: 'string', required: true },
            slug:  { type: 'string', required: true },
        },
        note: 'Array of { name, brand, slug } objects',
    },
    mentions: {
        target: 'shared',
        required: false,
        type: 'array',
        itemSchema: {
            type: { type: 'string', required: true },
            name: { type: 'string', required: true },
        },
        note: 'Array of { type, name } — brands or products mentioned',
    },
    dateModified: {
        target: 'shared',
        required: false,
        type: 'string',
        pattern: /^\d{4}-\d{2}-\d{2}$/,
        transform: 'timestamp',
        note: 'YYYY-MM-DD — converted to Firestore Timestamp on publish',
    },

    // ── Translation fields — written under translations.{lang} ────────────────

    inLanguage: {
        target: 'translation',
        required: true,
        type: 'string',
        enum: ['bg', 'en'],
    },
    title: {
        target: 'translation',
        required: true,
        type: 'string',
    },
    metaDescription: {
        target: 'translation',
        required: true,
        type: 'string',
        minLength: 140,
        maxLength: 160,
        note: '150–155 chars recommended; include primary keyword',
    },
    primaryKeyword: {
        target: 'translation',
        required: true,
        type: 'string',
    },
    tags: {
        target: 'translation',
        required: true,
        type: 'array',
    },
    status: {
        target: 'translation',
        required: true,
        type: 'string',
        enum: ['draft', 'published', 'archived'],
    },
    wordCount: {
        target: 'translation',
        required: false,
        type: 'number',
    },
    readingTimeMinutes: {
        target: 'translation',
        required: false,
        type: 'number',
    },
    sources: {
        target: 'translation',
        required: false,
        type: 'array',
    },

    // ── Internal fields — present in draft files, skipped in Firestore ─────────

    project:      { target: 'skip', note: 'Internal — identifies the project folder' },
    platform:     { target: 'skip', note: 'Internal — always "blog"' },
    robotsMeta:   { target: 'skip', note: 'Internal — set in Next.js page metadata, not in Firestore' },
    speakable:    { target: 'skip', note: 'Internal — CSS selector hint for TTS, handled by frontend' },
    sourcePdf:    { target: 'skip', note: 'Internal — reference to source PDF used during research' },
    sourceNotes:  { target: 'skip', note: 'Internal — free-text drafting notes' },
};
